function a(t){const e=new Date(t);return isNaN(e.getTime())?"Invalid Date":e.toLocaleDateString()}function n(t){const e=new Date(t);return isNaN(e.getTime())?"Invalid Date":e.toLocaleDateString("fr-FR",{weekday:"long",year:"numeric",month:"long",day:"numeric"})}function r(t){const e=new Date(t);return isNaN(e.getTime())?"Invalid Date":e.toLocaleDateString("fr-FR",{weekday:"long"})}export{a,n as f,r as j};
